    condition: randomCondition,
    humidity: 50 + Math.floor(Math.random() * 30)
  };
}

async function execute(args) {
  const length = Math.max(6, Math.min(64, Number(args.length) || 12));
  const includeSymbols = args.includeSymbols !== false;
  const includeNumbers = args.includeNumbers !== false;
  const letters = 'abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ';
  const numbers = '0123456789';
  const symbols = '!@#$%^&*()_+~`|}{[]:;?><,./-=';
  let chars = letters;
  if (includeNumbers) chars += numbers;
  if (includeSymbols) chars += symbols;
  let password = '';
  for (let i = 0; i < length; i++) {
    password += chars.charAt(Math.floor(Math.random() * chars.length));
  }
  return { password };
}

async function execute(args) {
  const amount = Number(args.amount) || 0;
  const from = (args.from || 'USD').toUpperCase();
  const to = (args.to || 'USD').toUpperCase();
  const rates = {
    USD: { EUR: 0.92, GBP: 0.79, JPY: 155.4, CAD: 1.36, USD: 1 },
    EUR: { USD: 1.09, GBP: 0.86, JPY: 168.9, CAD: 1.48, EUR: 1 },
    GBP: { USD: 1.27, EUR: 1.16, JPY: 196.7, CAD: 1.72, GBP: 1 }
  };
  const baseRates = rates[from] || rates['USD'];
  const rate = baseRates[to] || (from === to ? 1 : 1.1);
  const convertedAmount = amount * rate;
  return {
    from,
    to,
    amount,
    convertedAmount: Number(convertedAmount.toFixed(2)),
    rate: Number(rate.toFixed(4))
  };
}
